inCubic:(t)=>t*t*t,
outCubic:(t)=>1-(1-t)**3,
inOutCubic:(t)=>(t<0.5?4*t*t*t:1-(-2*t+2)**3/2),
inBack:(t)=>2.70158*t*t*t-1.70158*t*t,
outBack:(t)=>1+2.70158*(t-1)**3+1.70158*(t-1)**2,
