if(loopsLeft>0){
loopsLeft-=1;
fireCrossedScripts(previous,0);
spec.onLoop?.();
next=duration===0?0:duration+(next%duration);
time=next;
fireCrossedScripts(duration,next);
}else{
next=0;
time=next;
fireCrossedScripts(previous,next);
completed=true;
}
